={{ (() => {
  const d = $('Fusionner contact_id').first().json;
  const isRappelProspect = d.status_enum === 'pas_de_besoin_immediat_rappel';

  // Calculer la date d'échéance
  let dueDate;
  if (isRappelProspect && d.rappel_date) {
    dueDate = new Date(d.rappel_date + 'T09:00:00');
  } else {
    dueDate = new Date();
    dueDate.setDate(dueDate.getDate() + 3);
  }

  // Sujet de la tâche
  const subject = isRappelProspect
    ? 'Recontacter ' + d.contact_firstname + ' ' + d.contact_lastname + ' (' + d.company_name + ')'
    : 'Rappeler ' + d.contact_firstname + ' ' + d.contact_lastname + ' (' + d.company_name + ')';

  // Corps contextuel
  let body = '';
  const dateAppel = new Date(d.timestamp).toLocaleDateString('fr-FR');
  if (isRappelProspect) {
    body = 'Prospect contacté le ' + dateAppel + ' — Statut : Pas de besoin immédiat.\n';
    body += 'Le prospect a indiqué ne pas avoir de besoin dans l\'immédiat.\n';
    if (d.notes) body += '\nNotes de l\'appel :\n' + d.notes + '\n';
    body += '\nAction : Recontacter pour vérifier si un besoin s\'est créé depuis.';
    if (d.rappel_delai && d.rappel_delai !== 'custom') body += '\nDélai prévu : ' + d.rappel_delai + ' mois.';
  } else {
    body = 'Rappel automatique suite au statut : ' + d.status_raw + '\n';
    body += 'Contact envoyé depuis Decidento le ' + dateAppel;
    if (d.notes) body += '\n\nNotes : ' + d.notes;
  }

  const props = {
    hs_task_subject: subject,
    hs_task_body: body,
    hs_task_status: 'NOT_STARTED',
    hs_task_priority: isRappelProspect ? 'HIGH' : 'MEDIUM',
    hs_timestamp: dueDate.toISOString()
  };
  if (d.owner_id) props.hubspot_owner_id = d.owner_id;

  const associations = [
    { to: { id: parseInt(d.contact_id) }, types: [{ associationCategory: 'HUBSPOT_DEFINED', associationTypeId: 204 }] }
  ];

  try {
    const dealId = $('Créer Deal Prospection').first().json.body.id;
    if (dealId) associations.push({ to: { id: parseInt(dealId) }, types: [{ associationCategory: 'HUBSPOT_DEFINED', associationTypeId: 216 }] });
  } catch(e) {}

  return JSON.stringify({ properties: props, associations: associations });
})() }}

