// Récupérer l'URL de brochure résolue
let brochureUrl = '';
try {
  brochureUrl = $('Résoudre URL brochure').first().json.brochure_url || '';
} catch(e) { brochureUrl = ''; }

const item = $('Fusionner contact_id').first().json;
const firstname = item.contact_firstname || '';
const companyName = item.company_name || '';
const contactEmail = item.contact_email || '';
const contactId = item.contact_id || '';
const rdvDate = item.rdv_date || '';
const sendConfirmation = item.send_confirmation_email === true || item.send_confirmation_email === 'true';
const sendOffer = item.send_offer_email === true || item.send_offer_email === 'true';
const sendAppelSansReponse = item.send_appel_sans_reponse === true || item.send_appel_sans_reponse === 'true';

// Format RDV date in French
let rdvDateFormatted = '';
if (rdvDate) {
  try {
    const d = new Date(rdvDate);
    const jours = ['dimanche','lundi','mardi','mercredi','jeudi','vendredi','samedi'];
    const mois = ['janvier','février','mars','avril','mai','juin','juillet','août','septembre','octobre','novembre','décembre'];
    rdvDateFormatted = jours[d.getDay()] + ' ' + d.getDate() + ' ' + mois[d.getMonth()] + ' ' + d.getFullYear() + ' à ' + d.getHours().toString().padStart(2,'0') + 'h' + d.getMinutes().toString().padStart(2,'0');
  } catch(e) { rdvDateFormatted = rdvDate; }
}

const rdvLine = rdvDateFormatted ? '<p>Pour rappel, notre rendez-vous est prévu le <b>' + rdvDateFormatted + '</b>.</p>\n' : '';
const rdvLineText = rdvDateFormatted ? '\nPour rappel, notre rendez-vous est prévu le ' + rdvDateFormatted + '.\n' : '';

const signaturePlaceholder = '<div style="margin-top:24px;padding-top:16px;border-top:1px solid #dadce0;font-family:Arial,sans-serif;font-size:13px;color:#555;line-height:1.5"><b>%%COMMERCIAL_NAME%%</b><br>%%COMMERCIAL_TITLE%% | %%COMMERCIAL_COMPANY%%<br>%%COMMERCIAL_PHONE%%<br><a href="mailto:%%COMMERCIAL_EMAIL%%" style="color:#1a73e8;text-decoration:none">%%COMMERCIAL_EMAIL%%</a><br><a href="https://%%COMMERCIAL_WEBSITE%%" style="color:#1a73e8;text-decoration:none">%%COMMERCIAL_WEBSITE%%</a></div>';

const brochureLink = brochureUrl
  ? '<p>Je vous joins une brochure pour vous donner une vue d\'ensemble de notre approche :<br><a href="' + brochureUrl + '" style="color:#1a73e8;text-decoration:none">Télécharger la brochure</a></p>'
  : '';
const brochureLinkText = brochureUrl
  ? '\nBrochure : ' + brochureUrl
  : '';

// =============================================
// Email 1: Confirmation RDV + Présentation
// =============================================
const email1_subject = "Suite à notre échange — L'Atelier des Experts";
const email1_html = '<div style="font-family:Arial,sans-serif;font-size:14px;line-height:1.6;color:#222"><p>Bonjour ' + firstname + ',</p><p>Encore merci pour votre temps et pour la prise de rendez-vous.</p>' + rdvLine + '<p>Pour vous présenter brièvement notre approche à L\'Atelier des Experts, nous aidons les agences de communication à générer un chiffre d\'affaires supplémentaire, tout en apportant un vrai levier de valeur à leurs clients, grâce à la formation professionnelle 100\u00a0% financée.</p><p>Voici ce que nous mettons en place pour vous :</p><p>– Une conseillère formation dédiée pour vous accompagner tout au long du partenariat<br>– Le montage complet des dossiers, sans charge administrative pour vos équipes<br>– Un service de renouvellement annuel pour proposer chaque année de nouvelles formations à vos clients<br>– Une solution simple, fluide et entièrement prise en main de notre côté</p>' + brochureLink + '<p>Bien cordialement,</p>' + signaturePlaceholder + '</div>';
const email1_text = 'Bonjour ' + firstname + ',\n\nEncore merci pour votre temps et pour la prise de rendez-vous.' + rdvLineText + '\nPour vous présenter brièvement notre approche à L\'Atelier des Experts, nous aidons les agences de communication à générer un chiffre d\'affaires supplémentaire, tout en apportant un vrai levier de valeur à leurs clients, grâce à la formation professionnelle 100% financée.\n\nVoici ce que nous mettons en place pour vous :\n\n– Une conseillère formation dédiée\n– Le montage complet des dossiers\n– Un renouvellement annuel\n– Une solution simple et fluide' + brochureLinkText + '\n\nBien cordialement,\n%%COMMERCIAL_NAME%%';

// =============================================
// Email 2: Présentation de l'offre (standalone)
// =============================================
const email2_subject = "L'Atelier des Experts — Présentation de notre offre";
const email2_html = '<div style="font-family:Arial,sans-serif;font-size:14px;line-height:1.6;color:#222"><p>Bonjour ' + firstname + ',</p><p>Suite à notre récent échange, je souhaitais vous présenter plus en détail notre offre à L\'Atelier des Experts.</p><p>Nous aidons les agences de communication à générer un chiffre d\'affaires supplémentaire grâce à la formation professionnelle 100\u00a0% financée.</p><p>Voici ce que nous mettons en place :</p><p>– Une conseillère formation dédiée<br>– Le montage complet des dossiers<br>– La prise en charge du financement OPCO<br>– Un renouvellement annuel automatique</p>' + brochureLink + '<p>Bien cordialement,</p>' + signaturePlaceholder + '</div>';
const email2_text = 'Bonjour ' + firstname + ',\n\nSuite à notre récent échange, je souhaitais vous présenter notre offre à L\'Atelier des Experts.\n\nNous aidons les agences de communication à générer un CA supplémentaire grâce à la formation 100% financée.' + brochureLinkText + '\n\nBien cordialement,\n%%COMMERCIAL_NAME%%';

// =============================================
// Email 3: Appel sans réponse
// =============================================
const email3_subject = "J'ai tenté de vous joindre — L'Atelier des Experts";
const email3_html = '<div style="font-family:Arial,sans-serif;font-size:14px;line-height:1.6;color:#222"><p>Bonjour ' + firstname + ',</p><p>J\'ai tenté de vous joindre ce jour par téléphone, malheureusement sans succès.</p><p>Je me permets de vous contacter car je souhaitais vous présenter <b>Stafy</b>, une solution développée par <b>L\'Atelier des Experts</b> qui permet aux entreprises comme <b>' + companyName + '</b> de proposer à leurs clients des formations professionnelles 100\u00a0% financées, tout en générant un chiffre d\'affaires complémentaire.</p><p>En quelques mots, voici ce que nous mettons en place :</p><p>– Une conseillère formation dédiée pour accompagner vos clients de A à Z<br>– Le montage complet des dossiers de formation, sans charge pour vos équipes<br>– La prise en charge du financement auprès des OPCO<br>– Un renouvellement annuel pour fidéliser vos clients chaque année</p><p>Si le sujet vous intéresse, je serais ravi d\'en discuter avec vous lors d\'un court échange.<br><a href="%%BOOKING_URL%%" style="color:#1a73e8;text-decoration:none">Réserver un créneau</a></p><p>Bien cordialement,</p>' + signaturePlaceholder + '</div>';
const email3_text = 'Bonjour ' + firstname + ',\n\nJ\'ai tenté de vous joindre ce jour par téléphone, malheureusement sans succès.\n\nJe me permets de vous contacter car je souhaitais vous présenter Stafy, une solution développée par L\'Atelier des Experts qui permet aux entreprises comme ' + companyName + ' de proposer à leurs clients des formations 100% financées.\n\nEn quelques mots :\n– Une conseillère formation dédiée\n– Le montage complet des dossiers\n– La prise en charge du financement OPCO\n– Un renouvellement annuel\n\nRéserver un créneau : %%BOOKING_URL%%\n\nBien cordialement,\n%%COMMERCIAL_NAME%%';

return [{
  json: {
    ...item,
    email1_subject, email1_html, email1_text,
    email2_subject, email2_html, email2_text,
    email3_subject, email3_html, email3_text,
    send_confirmation_email: sendConfirmation,
    send_offer_email: sendOffer,
    send_appel_sans_reponse: sendAppelSansReponse,
    contact_email: contactEmail,
    contact_firstname: firstname,
    contact_id: contactId
  }
}];

// Annuaire complémentaire des commerciaux (titre, company, phone)
const ANNUAIRE = {
  '80222699': { title: 'Commercial Partenaires', company: "Atelier des Experts\u00a9", phone: '01 84 75 47 20' },
  '51816547': { title: 'Commercial', company: "Atelier des Experts\u00a9", phone: '01 23 45 67 89' },
  '31958923': { title: 'Commercial', company: "Atelier des Experts\u00a9", phone: '01 84 75 47 20' },
  '52585251': { title: 'Chargée de développement', company: "Atelier des Experts\u00a9", phone: '01 84 75 47 20' },
  '80309654': { title: 'Chargée de développement', company: "Atelier des Experts\u00a9", phone: '01 84 75 47 20' }
};

const DEFAULT_INFO = {
  title: 'Commercial',
  company: "Atelier des Experts\u00a9",
  phone: '01 84 75 47 20'
};

// Données du flow
const prevData = $('Préparer emails').first().json;
const ownerResponse = $('Récupérer owner HubSpot').first().json;
const ownerBody = ownerResponse.body || ownerResponse;

const ownerId = $('Résoudre owner ID').first().json.owner_id || '';
const ownerFirstName = ownerBody.firstName || '';
const ownerLastName = ownerBody.lastName || '';
const ownerEmail = ownerBody.email || '';
const ownerName = `${ownerFirstName} ${ownerLastName}`.trim();
const ownerUserId = String(ownerBody.userId || '');

// Récupérer le meeting link dynamiquement via l'API
let bookingUrl = '';
try {
  const meetingLinksResponse = $('Lister meeting links').first().json;
  const meetingLinks = (meetingLinksResponse.body && meetingLinksResponse.body.results) || meetingLinksResponse.results || [];

  // Matcher par organizerUserId (= HubSpot userId de l'owner)
  // Prendre le lien PERSONAL_LINK (pas les liens spéciaux comme "Renouvellement")
  const matched = meetingLinks.find(ml => 
    String(ml.organizerUserId) === ownerUserId && ml.type === 'PERSONAL_LINK'
  );
  if (matched) {
    bookingUrl = matched.link || '';
  }
} catch(e) {
  // Fallback si le nœud meeting links a échoué
  bookingUrl = '';
}

if (!bookingUrl) {
  bookingUrl = 'https://meetings-eu1.hubspot.com/atelier-des-experts';
}

// Fusionner HubSpot owner + annuaire complémentaire
const extra = ANNUAIRE[ownerId] || DEFAULT_INFO;

const sig = {
  name: ownerName || "L'Atelier des Experts",
  title: extra.title,
  company: extra.company,
  phone: extra.phone,
  email: ownerEmail || 'contact@atelierdesexperts.fr',
  website: 'atelierdesexperts.fr',
  bookingUrl: bookingUrl
};

// Générer le HTML de signature (style Gmail)
const signatureHtml = `<div style="margin-top:24px;padding-top:16px;border-top:1px solid #dadce0;font-family:Arial,sans-serif;font-size:13px;color:#555;line-height:1.5">
<b>${sig.name}</b><br>
${sig.title} | ${sig.company}<br>
${sig.phone}<br>
<a href="mailto:${sig.email}" style="color:#1a73e8;text-decoration:none">${sig.email}</a><br>
<a href="https://${sig.website}" style="color:#1a73e8;text-decoration:none">${sig.website}</a>
</div>`;

// Remplacer les placeholders %%...%% dans les emails
function replacePlaceholders(text) {
  return text
    .replace(/%%COMMERCIAL_NAME%%/g, sig.name)
    .replace(/%%COMMERCIAL_TITLE%%/g, sig.title)
    .replace(/%%COMMERCIAL_COMPANY%%/g, sig.company)
    .replace(/%%COMMERCIAL_PHONE%%/g, sig.phone)
    .replace(/%%COMMERCIAL_EMAIL%%/g, sig.email)
    .replace(/%%COMMERCIAL_WEBSITE%%/g, sig.website);
}

const email1_html = replacePlaceholders(prevData.email1_html || '');
const email1_text = replacePlaceholders(prevData.email1_text || '');
const email2_html = replacePlaceholders(prevData.email2_html || '');
const email2_text = replacePlaceholders(prevData.email2_text || '');



// Récupérer l'URL brochure directement (les branches sont synchronisées par le Merge)
let brochureUrl = '';
try {
  brochureUrl = $('Résoudre URL brochure').first().json.brochure_url || '';
} catch(e) { brochureUrl = ''; }

// Helper: capitalize chaque mot (gère parenthèses, tirets)
function capitalize(str) {
  if (!str) return '';
  // Nettoyer les \n et espaces multiples
  str = str.replace(/\n/g, ' ').replace(/\s+/g, ' ').trim();
  return str.split(' ').map(w => {
    if (!w) return '';
    // Si le mot commence par ( ou - ou ', capitalize la lettre suivante
    let prefix = '';
    let rest = w;
    while (rest.length > 0 && /[^a-zA-ZÀ-ÿ0-9]/.test(rest[0])) {
      prefix += rest[0];
      rest = rest.slice(1);
    }
    if (!rest) return prefix;
    return prefix + rest.charAt(0).toUpperCase() + rest.slice(1).toLowerCase();
  }).join(' ');
}

return [{
  json: {
    ...prevData,
    contact_firstname: capitalize(prevData.contact_firstname || ''),
    company_name: capitalize(prevData.company_name || ''),
    brochure: brochureUrl,
    commercial_name: sig.name,
    commercial_email: sig.email,
    commercial_title: sig.title,
    commercial_phone: sig.phone,
    commercial_website: sig.website,
    url_meeting: sig.bookingUrl,
    signature_html: signatureHtml,
    email1_html,
    email1_text,
    email2_html,
    email2_text
  }
}];

// Résoudre l'URL de brochure en fonction du champ offer_brochure
const offerBrochure = ($('Préparer les données').first().json.offer_brochure || '').toLowerCase();
const filesResponse = $('Lister brochures HubSpot').first().json;

// Extraire la liste de fichiers depuis la réponse API HubSpot Files
const files = filesResponse.body?.results || filesResponse.results || [];

let brochureUrl = '';

if (offerBrochure && files.length > 0) {
  // Logique de matching : chercher dans les noms de fichiers
  for (const file of files) {
    const fileName = (file.name || '').toLowerCase();

    if (offerBrochure.includes('web') && fileName.includes('agence')) {
      brochureUrl = file.url || '';
      break;
    }
    if (offerBrochure.includes('staf') && fileName.includes('stafy')) {
      brochureUrl = file.url || '';
      break;
    }
    if (offerBrochure.includes('generique') && fileName.includes('generique')) {
      brochureUrl = file.url || '';
      break;
    }
    if (offerBrochure.includes('générique') && fileName.includes('generique')) {
      brochureUrl = file.url || '';
      break;
    }
  }
}

// Fallback : si pas de match, on laisse vide
return [{ json: { brochure_url: brochureUrl } }];

// Nettoyer le nom d'entreprise (retirer \n et espaces multiples)
function cleanStr(s) {
  if (!s) return '';
  return s.replace(/\n/g, ' ').replace(/\s+/g, ' ').trim();
}

const body = $input.first().json.body;
const contact = body.contact || {};
const company = body.company || {};

// Utiliser firstname/lastname envoyés par l'extension (champs éditables)
const firstname = cleanStr(contact.firstname || '');
const lastname = cleanStr(contact.lastname || '');

const statusMap = {
  'Message vocal laissé': 'message_vocal_laisse',
  'Injoignable': 'injoignable',
  'Rendez-vous pris': 'rendez_vous_pris',
  'Ne plus rappeler': 'ne_plus_rappeler',
  'Déjà appelé': 'deja_appele',
  'Pas intéressé': 'pas_interesse',
  'Déjà en partenariat': 'deja_en_partenariat',
  'A raccroché': 'a_raccroche',
