const email2_text = 'Bonjour ' + firstname + ',\n\nSuite à notre récent échange, je souhaitais vous présenter notre offre à L\'Atelier des Experts.\n\nNous aidons les agences de communication à générer un CA supplémentaire grâce à la formation 100% financée.' + brochureLinkText + '\n\nBien cordialement,\n%%COMMERCIAL_NAME%%';

// =============================================
