// =============================================
const email3_subject = "J'ai tenté de vous joindre — L'Atelier des Experts";
const email3_html = '<div style="font-family:Arial,sans-serif;font-size:14px;line-height:1.6;color:#222"><p>Bonjour ' + firstname + ',</p><p>J\'ai tenté de vous joindre ce jour par téléphone, malheureusement sans succès.</p><p>Je me permets de vous contacter car je souhaitais vous présenter <b>Stafy</b>, une solution développée par <b>L\'Atelier des Experts</b> qui permet aux entreprises comme <b>' + companyName + '</b> de proposer à leurs clients des formations professionnelles 100\u00a0% financées, tout en générant un chiffre d\'affaires complémentaire.</p><p>En quelques mots, voici ce que nous mettons en place :</p><p>– Une conseillère formation dédiée pour accompagner vos clients de A à Z<br>– Le montage complet des dossiers de formation, sans charge pour vos équipes<br>– La prise en charge du financement auprès des OPCO<br>– Un renouvellement annuel pour fidéliser vos clients chaque année</p><p>Si le sujet vous intéresse, je serais ravi d\'en discuter avec vous lors d\'un court échange.<br><a href="%%BOOKING_URL%%" style="color:#1a73e8;text-decoration:none">Réserver un créneau</a></p><p>Bien cordialement,</p>' + signaturePlaceholder + '</div>';
const email3_text = 'Bonjour ' + firstname + ',\n\nJ\'ai tenté de vous joindre ce jour par téléphone, malheureusement sans succès.\n\nJe me permets de vous contacter car je souhaitais vous présenter Stafy, une solution développée par L\'Atelier des Experts qui permet aux entreprises comme ' + companyName + ' de proposer à leurs clients des formations 100% financées.\n\nEn quelques mots :\n– Une conseillère formation dédiée\n– Le montage complet des dossiers\n– La prise en charge du financement OPCO\n– Un renouvellement annuel\n\nRéserver un créneau : %%BOOKING_URL%%\n\nBien cordialement,\n%%COMMERCIAL_NAME%%';

return [{
