}];

// Annuaire complémentaire des commerciaux (titre, company, phone)
const ANNUAIRE = {
  '80222699': { title: 'Commercial Partenaires', company: "Atelier des Experts\u00a9", phone: '01 84 75 47 20' },
  '51816547': { title: 'Commercial', company: "Atelier des Experts\u00a9", phone: '01 23 45 67 89' },
  '31958923': { title: 'Commercial', company: "Atelier des Experts\u00a9", phone: '01 84 75 47 20' },
  '52585251': { title: 'Chargée de développement', company: "Atelier des Experts\u00a9", phone: '01 84 75 47 20' },
  '80309654': { title: 'Chargée de développement', company: "Atelier des Experts\u00a9", phone: '01 84 75 47 20' }
};

const DEFAULT_INFO = {
  title: 'Commercial',
  company: "Atelier des Experts\u00a9",
  phone: '01 84 75 47 20'
};

// Données du flow
const prevData = $('Préparer emails').first().json;
const ownerResponse = $('Récupérer owner HubSpot').first().json;
const ownerBody = ownerResponse.body || ownerResponse;

const ownerId = $('Résoudre owner ID').first().json.owner_id || '';
const ownerFirstName = ownerBody.firstName || '';
const ownerLastName = ownerBody.lastName || '';
const ownerEmail = ownerBody.email || '';
const ownerName = `${ownerFirstName} ${ownerLastName}`.trim();
const ownerUserId = String(ownerBody.userId || '');

// Récupérer le meeting link dynamiquement via l'API
let bookingUrl = '';
try {
  const meetingLinksResponse = $('Lister meeting links').first().json;
  const meetingLinks = (meetingLinksResponse.body && meetingLinksResponse.body.results) || meetingLinksResponse.results || [];

  // Matcher par organizerUserId (= HubSpot userId de l'owner)
  // Prendre le lien PERSONAL_LINK (pas les liens spéciaux comme "Renouvellement")
  const matched = meetingLinks.find(ml => 
    String(ml.organizerUserId) === ownerUserId && ml.type === 'PERSONAL_LINK'
  );
  if (matched) {
    bookingUrl = matched.link || '';
  }
} catch(e) {
  // Fallback si le nœud meeting links a échoué
  bookingUrl = '';
}

if (!bookingUrl) {
  bookingUrl = 'https://meetings-eu1.hubspot.com/atelier-des-experts';
}

// Fusionner HubSpot owner + annuaire complémentaire
const extra = ANNUAIRE[ownerId] || DEFAULT_INFO;

const sig = {
  name: ownerName || "L'Atelier des Experts",
  title: extra.title,
  company: extra.company,
  phone: extra.phone,
  email: ownerEmail || 'contact@atelierdesexperts.fr',
